where es_plantilla and nombre in (
  'Full Body 2 días — Principiante',
  'Torso/Pierna 4 días — Intermedio',
  'Pierna & Glúteo 3 días — Énfasis inferior',
  'Definición Full Body 3 días — Superseries'
);

